using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page fetching capabilities for the research agent.
/// </summary>
internal sealed partial class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
    };

    [Description("Search the web for information on a given query. Returns a list of result titles, URLs, and snippets.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            string encoded = WebUtility.UrlEncode(query);
            string url = $"https://html.duckduckgo.com/html/?q={encoded}";
            string html = await s_httpClient.GetStringAsync(url, cancellationToken);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
            {
                return $"No results found for: {query}";
            }

            return string.Join("\n\n", results.Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Returns the extracted text (truncated to ~4000 chars).")]
    public static async Task<string> FetchWebPage(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            string html = await s_httpClient.GetStringAsync(url, cancellationToken);
            string text = StripHtml(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
            {
                text = text[..maxLength] + "\n...[truncated]";
            }

            return string.IsNullOrWhiteSpace(text)
                ? "Page returned no readable text content."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();
        var matches = ResultPattern().Matches(html);

        foreach (Match match in matches)
        {
            if (results.Count >= 5)
                break;

            string rawUrl = WebUtility.HtmlDecode(match.Groups["url"].Value);
            string title = StripHtml(WebUtility.HtmlDecode(match.Groups["title"].Value)).Trim();
            string snippet = StripHtml(WebUtility.HtmlDecode(match.Groups["snippet"].Value)).Trim();

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            if (rawUrl.Contains("uddg="))
            {
                var uri = new Uri("https://duckduckgo.com" + rawUrl);
                string? decoded = System.Web.HttpUtility.ParseQueryString(uri.Query).Get("uddg");
                if (!string.IsNullOrEmpty(decoded))
                    rawUrl = decoded;
            }

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add(new SearchResult(title, rawUrl, snippet));
            }
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        string noScript = ScriptStylePattern().Replace(html, " ");
        string noTags = TagPattern().Replace(noScript, " ");
        string decoded = WebUtility.HtmlDecode(noTags);
        return CollapseWhitespacePattern().Replace(decoded, " ").Trim();
    }

    [GeneratedRegex("""<a[^>]+href="(?<url>[^"]*)"[^>]*class="[^"]*result__a[^"]*"[^>]*>(?<title>.*?)</a>.*?<a[^>]+class="[^"]*result__snippet[^"]*"[^>]*>(?<snippet>.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultPattern();

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStylePattern();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagPattern();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex CollapseWhitespacePattern();

    private sealed record SearchResult(string Title, string Url, string Snippet);
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides in-memory note-taking capabilities for the research agent.
/// </summary>
internal sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and content. Use this to record key findings as you research.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The content/body of the note")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes. Use this to review what you've learned before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
    }

    private sealed record Note(string Title, string Content, DateTime SavedAt);
}

