 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;
 using ResearchAgent.Tools;

 // --- Configuration ---
 string apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable to run this app.");

 const string modelId = "gpt-4o-mini-2024-07-18";

 // --- Build the IChatClient via MEAI abstraction ---
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Define tools ---
 var noteTool = new NoteTool();
 var tools = new AITool[]
 {
     AIFunctionFactory.Create(WebSearchTool.SearchWeb),
     AIFunctionFactory.Create(WebSearchTool.FetchWebPage),
     AIFunctionFactory.Create(noteTool.SaveNote),
     AIFunctionFactory.Create(noteTool.GetNotes),
 };

 // --- Create the agent ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a thorough research agent. When given a topic you:

         1. Search the web for relevant, up-to-date information using multiple queries.
         2. Fetch promising web pages to gather details.
         3. Save key findings as notes using the note-taking tool.
         4. After gathering enough information, review your notes.
         5. Produce a well-structured summary with sections, key facts, and source URLs.

         Always cite your sources. Be factual and concise.
         """,
     name: "ResearchAgent",
     description: "Researches topics by searching the web and summarizing findings",
     tools: tools);

 // --- Get the research topic ---
 string topic;
 if (args.Length > 0)
 {
     topic = string.Join(' ', args);
 }
 else
 {
     Console.Write("Enter a research topic: ");
     topic = Console.ReadLine()?.Trim() ?? string.Empty;
 }

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.Error.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 // --- Run the agent with streaming output ---
 var runOptions = new ChatClientAgentRunOptions(
     new ChatOptions { Temperature = 0f });

 await foreach (var update in agent.RunStreamingAsync(
     $"Research the following topic and provide a comprehensive summary:\n\n{topic}",
     session: null,
     options: runOptions))
 {
     Console.Write(update.Text);
 }

 Console.WriteLine();

